prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?task ?taskName ?taskType ?loopType WHERE {
  ?task a bboExt:ChoreographyTask .
  ?task tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_7e6c8e81_8977_4cbd_818d_dec74bfc816b> .
  OPTIONAL { ?task bbo:name ?taskName . }
  OPTIONAL { ?task bboExt:loopType ?loopType . }
  BIND("ChoreographyTask" AS ?taskType)
}

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?startEvent ?startName WHERE {
  ?startEvent a bboExt:StartEvent .
  ?startEvent tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_7e6c8e81_8977_4cbd_818d_dec74bfc816b> .
  OPTIONAL { ?startEvent bbo:name ?startName . }
}
